#include <iostream>
using namespace std;

int main() {
    // Integer variable
    int a = 10;
    int b = 3;

    // Floating point variables
    float pi = 3.14f;
    double e = 2.71828;

    // Character variable
    char grade = 'A';

    // Arithmetic operators
    int sum = a + b;        // Addition
    int diff = a - b;       // Subtraction
    int prod = a * b;       // Multiplication
    int quot = a / b;       // Division (integer)
    int rem = a % b;        // Modulus (remainder)

    // Increment and decrement
    int x = 5;
    x++;                    // Post-increment
    ++x;                    // Pre-increment

    // Output results
    cout << "Sum: " << sum << endl;
    cout << "Difference: " << diff << endl;
    cout << "Product: " << prod << endl;
    cout << "Quotient: " << quot << endl;
    cout << "Remainder: " << rem << endl;
    cout << "Pi: " << pi << endl;
    cout << "E: " << e << endl;
    cout << "Grade: " << grade << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // Integer variables
    int x = 5;
    int y = 10;

    // Boolean variable
    bool isTrue = true;

    // Comparison operators (return boolean values)
    bool equal = (x == y);          // Equal to
    bool notEqual = (x != y);       // Not equal to
    bool greater = (y > x);         // Greater than
    bool less = (x < y);            // Less than
    bool greaterEq = (y >= x);     // Greater or equal
    bool lessEq = (x <= y);         // Less or equal

    // Logical operators
    bool logicAnd = (x > 0) && (y > 0);   // Logical AND
    bool logicOr = (x < 0) || (y < 0);    // Logical OR
    bool logicNot = !isTrue;              // Logical NOT

    // Type casting (explicit conversion)
    int num1 = 10;
    int num2 = 3;
    double result = (double)num1 / num2;  // Explicit cast to double

    int num3 = 7;
    int num4 = 2;
    double result2 = num3 / num4;          // Integer division (loses precision)
    double result3 = static_cast<double>(num3) / num4;  // Using static_cast

    // Output results
    cout << "Equal: " << equal << endl;
    cout << "Not Equal: " << notEqual << endl;
    cout << "Greater: " << greater << endl;
    cout << "Less: " << less << endl;
    cout << "AND: " << logicAnd << endl;
    cout << "OR: " << logicOr << endl;
    cout << "NOT: " << logicNot << endl;
    cout << "Cast Result: " << result << endl;
    cout << "Int Division: " << result2 << endl;
    cout << "static_cast Result: " << result3 << endl;

    return 0;
}
